# acme_claude/retry.py  — guest contribution example
from __future__ import annotations
import time
from typing import Callable, TypeVar

T = TypeVar("T")

def with_exponential_backoff(
    fn: Callable[[], T],
    *,
    max_attempts: int = 4,
    base_delay: float = 0.5,
    jitter: bool = True,
) -> T:
    """Retry fn with exponential back-off on RateLimitError."""
    import random
    from anthropic import RateLimitError

    for attempt in range(max_attempts):
        try:
            return fn()
        except RateLimitError:
            if attempt == max_attempts - 1:
                raise
            delay = base_delay * (2 ** attempt)
            if jitter:
                delay *= 0.5 + random.random() * 0.5
            time.sleep(delay)
    raise RuntimeError("unreachable")  # type: ignore[return-value]

# tests/test_retry.py  — tests are required before PR opens
import pytest
from unittest.mock import MagicMock, call
from anthropic import RateLimitError
from acme_claude.retry import with_exponential_backoff

def test_succeeds_on_first_attempt():
    fn = MagicMock(return_value="ok")
    assert with_exponential_backoff(fn, max_attempts=3) == "ok"
    fn.assert_called_once()

def test_retries_on_rate_limit(monkeypatch):
    monkeypatch.setattr("time.sleep", lambda _: None)
    calls = [RateLimitError("limit"), RateLimitError("limit"), "success"]
    fn = MagicMock(side_effect=calls)
    assert with_exponential_backoff(fn, max_attempts=3, jitter=False) == "success"
    assert fn.call_count == 3

def test_raises_after_max_attempts(monkeypatch):
    monkeypatch.setattr("time.sleep", lambda _: None)
    fn = MagicMock(side_effect=RateLimitError("limit"))
    with pytest.raises(RateLimitError):
        with_exponential_backoff(fn, max_attempts=2, jitter=False)
